// // This module compares two 2-bit numbers and outputs whether A is less than or equal to B
module comparator(
    input [1:0] A,
    input [1:0] B,
    output reg A_gt_B,
    output reg A_eq_B,
    output reg A_lt_B
);

always @(*) begin
    A_gt_B = (A > B);
    A_eq_B = (A == B);
    A_lt_B = (A < B);
end

endmodule
